const Q_PHYSICS_2018_MODEL_I=[{"id": "objective>Physics>2018 Model I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The volume of a cubical metal changes from 200cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at 30°C to 204cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>, the new temperature is ...... <br/> [Linear expansivity of the block is 3.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">47°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">49°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">51°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">53°C</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 200cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 204cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 30°C <br/> α = 3.2 &#215; 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ? <br/> Recall: <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">γ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>-V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>Δθ</td></tr></table></div> <br/> γ = 3α <br/> γ = 3 × 3.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> = 9.6 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">9.6</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4<hr size=\"1\" />200Δθ</td></tr></table></div> <br/> 200×∆θ×9.6×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> = 4 <br/> Δθ × 19.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> = 4 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Δθ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4<hr size=\"1\" />1.92×10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">40<hr size=\"1\" />1.92</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">20.8°C</td></tr></table></div> <br/> N.B: Δθ = θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> 20.8°C = θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - 30°C <br/> θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 50.8°C ≈ 51°C <br/> </div>", "topic": "THERMAL EXPANSION : SOLIDS"}, {"id": "objective>Physics>2018 Model I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these works based on the principle of mirror inclination?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">galvanometer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kaleidoscope</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sextant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">microscope</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A sextant is a navigational instrument that works based on the principle of mirror inclination. It uses two mirrors—one fixed and one adjustable—to measure the angle between celestial objects and the horizon. By adjusting the inclination of the movable mirror, navigators can precisely determine their latitude at sea. <br/>  <br/> A kaleidoscope does use mirrors, but it does not operate based on mirror inclination. Instead, it relies on multiple reflections within a set arrangement of mirrors to create symmetrical patterns. The mirrors inside a kaleidoscope are fixed at specific angles (typically 60°) and do not change inclination during use. <br/>  <br/> In contrast, a sextant actively uses the inclination of mirrors to measure angles between celestial objects and the horizon, making it the correct answer.</div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>2018 Model I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements describes a body in a stable equilibrium correctly?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">person walking on a tight rope </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ball on a smooth horizontal table </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ball resting on an inverted hemispherical bowl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ball in the middle of a hemispherical bowl</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A ball resting on anball in the middle of a hemispherical bowl describe a body in stable equilibrium. <br/> </div>", "topic": "EQUILIBRIUM OF FORCES : CENTRE OF GRAVITY AND STABILITY"}, {"id": "objective>Physics>2018 Model I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A box is pulled along a horizontal surface with the aid of a rope of length 80cm. One end of the rope is attached to the box while the other end is held 48cm above the ground. If the horizontal component of force on the box is 80N, the tension in the rope is ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">64N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">80N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">133.3N</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">adj = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">0.8<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> - 0.48<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>&nbsp;</span> = 0.64 <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">cosθ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.64<hr size=\"1\" />0.8</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4<hr size=\"1\" />5</td></tr></table></div> <br/> Horizontal component of force = Tcosθ <br/>  <br/> T(4/5) = 80 or T = 100N</div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2018 Model I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A fixed mass of gas at a temperature of 27°C is heated at constant volume until the pressure is double. The final temperature of the gas is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">327°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">163.5°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">54°C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">13.5°C</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 27 + 273 = 300K <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2</td></tr></table></div> <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 2T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 2 × 300 = 600K = 327°C</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2018 Model I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An object of mass 10kg initially at rest on a horizontal surface is subjected to a horizontal force of 40N. The body moves in the direction of the applied force with an acceleration of 3ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>. The work done against friction after moving the object for two seconds is ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">240J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">180J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">120J</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60J</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The applied force of 40N is used in overcoming friction and ingiving the object an acceleration. <br/> Force accelerating the object = ma = 10(3) = 30N <br/> Frictional force = 40 - 30 = 10N <br/> After 2s, the object is moved through distance  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">s</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">at<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">(3)(2)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6m</td></tr></table></div> <br/> Workdone against friction = frictional force × distance  <br/> = 10 × 6 = 60J</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2018 Model I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> If the above system is at equilibrium, the values of T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> and T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span>csc 75° and 50&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span> csc 75°</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span>csc 75° and 50&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span> csc 75° <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">50&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">3&nbsp;</span>csc 15° and 50&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span> csc 15° <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">None of the above</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2018 Model I/qqjiyl.png\" style=\"position:relative;max-width:100%;\"/> <br/> <img src=\"2018 Model I/cnqbkw.png\" style=\"position:relative;max-width:100%;\"/> <br/> <img src=\"2018 Model I/ovuaro.png\" style=\"position:relative;max-width:100%;\"/> <br/> 100 = T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>cos60° <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100<hr size=\"1\" />cos60°</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">200N</td></tr></table></div> <br/> 100N = T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>sin45° <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 100/sin45° = 100 ÷ 1/&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span> = 100&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span> N <br/> Therefore, none of the options is correct</div>", "topic": "EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES"}, {"id": "objective>Physics>2018 Model I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A spring balance measures <br/> I. the mass of the body hung on it <br/> II. the earth's gravitational pull on the body hung on it <br/> III. the weight of the body hung on it. <br/> Which of the above statements is (are) correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> A spring balance indicates the extension in a spring due to the weight (or gravitational pull) of a body hung on it. [The reading on a spring balannce will vary, for instance with altitude even though the mass of the body is constant]</div>", "topic": "MEASUREMENTS AND UNITS : MASS"}, {"id": "objective>Physics>2018 Model I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The dimension of Newton's gravitational constant is M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span>L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">z</span>, the value of x+y/z is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">-2</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: From Newton's Law of Universal Gravitation <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">GM<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">G</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Fr<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">G</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">MLT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>×L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> G = M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> Equate this to M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span>L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">z</span> <br/> M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">x</span>L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">y</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">z</span> = M<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>L<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>T<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> x = -1, y = 3 and z = -2 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x+y<hr size=\"1\" />2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-1+3<hr size=\"1\" />-2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />-2</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-1</td></tr></table></div></div>", "topic": "MEASUREMENTS AND UNITS : DIMENSIONS"}, {"id": "objective>Physics>2018 Model I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A rainbow is formed when sunlight is incident on water droplets suspended in the air due to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diffraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dispersion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">interference</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Rainbow is  a consequence of dispersion of light. These colors are often observed as light passes through a triangular prism. Upon passage through the prism, the white light is separated into its component colors - red, orange, yellow, green, blue and violet. The separation of visible light into its different colors is known as dispersion.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS"}, {"id": "objective>Physics>2018 Model I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A ball is released from a height of 125m above the ground. The time taken to reach the ground is ...... [g = 10m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10s</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">H= 125m, g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>, T = ? <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">2H<hr size=\"1\" />g</td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">250<hr size=\"1\" />10</td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> T = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">25&nbsp;</span> <br/> T = 5s</div>", "topic": "MOTION: MOTION UNDER GRAVITY"}, {"id": "objective>Physics>2018 Model I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a Daniel cell, the depolarizer, cathode and anode respectively are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Copper sulphate, Copper and Zinc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Manganese dioxide, Copper and Zinc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sulphuric acid, Lead oxide and Lead</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Potassium hydroxide, Nickel and Zinc</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Copper sulphate, Copper and Zinc is the correct answer <br/>  <br/> In a Daniel cell, CuSO4 is the depolarizer, copper vessel is the cathode and Zinc rod is the anode</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2018 Model I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the points on the waveform shown in the figure is (are) exactly in phase with point a? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">b and c only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">d and f only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">d and e only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">b, d and f only</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Points d and f are located at corresponding points (just before the crest) as point a. Thus ad = df = wavelength of the wave.</div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2018 Model I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body accelerates uniformly from rest for a time t. The kinetic energy of the body at t <br/> I. is directly proportional to the displacement  <br/> II. is directly proportional to the square of the instantaneous velocity <br/> III. is directly proportional to t<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> IV. depends on the value of the acceleration <br/> Which of the above statements is (are) correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and IV</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 2as and v = at, we can write  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">K.E</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">m(2as)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">m(at)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">ma<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>t<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> .e the K.E is directly proportional to s and to t<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> and it also depends on the acceleration a.</div>", "topic": "WORK, ENERGY AND POWER"}, {"id": "objective>Physics>2018 Model I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A ball of mass 20Kg strikes a vertical wall and rebounce with the same velocity. If the impulse received is 1.2KNs. <br/> The magnitude of the velocity is ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">30m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60m/s</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">mass, m = 20kg <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = x <br/> Impulse, I = 1.2kNs = 1200Ns <br/> Recal: Impulse = m(v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> - v<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) <br/> In this case, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = -V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>, since the body rebounds with the same velocity but in the opposite direction <br/> I = m(V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> - (-V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)) <br/> I = m(V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>) <br/> I = m(2V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>) <br/> 1200 = 20(2V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1200<hr size=\"1\" />40</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">30ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td></tr></table></div></div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2018 Model I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What type of wave is emitted by a loud speaker?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Transverse</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Longitudinal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gamma</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Radio</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A loudspeaker emits sound waves, which are longitudinal waves. In longitudinal waves, the displacement of the medium is in the same direction as, or the opposite direction to, the direction of propagation of the wave. This is different from transverse waves where the displacement of the medium is at right angles to the direction of propagation of the wave. Gamma and radio waves are types of electromagnetic waves, not mechanical waves like sound.</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2018 Model I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A body can undergo the following types of motion except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">random</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rotational</div>", "<div style=\"font-family:Cambria;font-size:17px;\">translational</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relative</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A body cannot undergo \"relative motion\". Relative motion usually involves two bodies.</div>", "topic": "MOTION: TYPES OF MOTION"}, {"id": "objective>Physics>2018 Model I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mouthpiece of a telephone primarily convert sound energy into</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mechanical</div>", "<div style=\"font-family:Cambria;font-size:17px;\">electrical</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chemical</div>", "<div style=\"font-family:Cambria;font-size:17px;\">heat</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mouthpiece of a telephone primarily converts sound energy into electrical energy. This is done through a process called transduction, where the sound waves cause a diaphragm in the mouthpiece to vibrate. These vibrations are then converted into electrical signals that can be transmitted over a distance.</div>", "topic": "MAGNETIC FIELD"}, {"id": "objective>Physics>2018 Model I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The bob that will be in resonance with bob X is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">P </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Q</div>", "<div style=\"font-family:Cambria;font-size:17px;\">R</div>", "<div style=\"font-family:Cambria;font-size:17px;\">T</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The bob that will resonate with X must be of the same length as X, and from the diagram given, R and X are of the same length. Hence, R will resonant with X.</div>", "topic": "MOTION: SIMPLE HARMONIC MOTION (S.H.M)"}, {"id": "objective>Physics>2018 Model I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above illustrates a beaker of water being heated. It is observed that as the bubbles rise they get bigger in size. The reason for this observation is ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water pressure on the bubbles decreases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">density of water increases with rise in temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">volume of water increases with rise in temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">atmospheric pressure on the bubbles decreases</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Atmospheric pressure and water pressure (due to depth) act on the bubble simultaneously, but as the bubble rises water pressure reduces.</div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2018 Model I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The force that tend to pull an object undergoing circular motion towards the centre is ......</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">centripetal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">centrifugal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tension</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reaction</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The force that tends to pull an object undergoing circular motion towards the centre is the centripetal force, centrifugal force will pull it away from the centre.</div>", "topic": "MOTION: MOTION IN A CIRCLE"}, {"id": "objective>Physics>2018 Model I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above illustrates a micrometer screw gauge. Determine its reading </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.44mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.46mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.86mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.96mm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram in the question is that of a micrometer screw gauge. <br/> Recall: To take the readings of a micrometer screw gauge, we take the sum of the main scale reading and the micro scale reading. <br/> Micrometer Reading = Mainscale reading + Microscale reading <br/> MR = MSR + msr ------ (1) <br/> MR = 2.00m + 0.46mm <br/>  = 2.46mm</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2018 Model I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The net downward force on a metal ball falling through a liquid at the terminal velocity is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">its weight</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the viscous force </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the upthrust</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a metal ball is falling through a liquid at terminal velocity, it means that it has reached a constant speed. At this point, the net force acting on the ball is zero because the downward force (weight) is balanced by the upward forces (viscous force and upthrust). This is in accordance with Newton's first law of motion which states that an object in motion will continue to move at a constant velocity unless acted upon by a net external force.</div>", "topic": "FRICTION : VISCOSITY AND TERMINAL VELOCITY"}, {"id": "objective>Physics>2018 Model I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A missile was projected horizontally from the top of a building, if it takes a velocity of 3m/s to reach the floor. The range of the projection of the projectile is 9m, determine the height of the building?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">9m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">18m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">45m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">90m</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2018 Model I/99aokj.png\" style=\"position:relative;max-width:100%;\"/> <br/> Recall: <br/> R = UxT ------ * <br/> 9 = 3T <br/> T = 3s <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">H</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">gT<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">H</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">10</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">(3)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/>  = 45m</div>", "topic": "MOTION: PROJECTILES"}, {"id": "objective>Physics>2018 Model I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Some ice crystals are held down at the bottom of a glass tube with a metal wire gauze. The tube is now filled with water and heated near the top. The water boils while the ice remains unmelted because  <br/> I. water is a poor conductor of heat <br/> II. glass is a poor conductor of heat <br/> III. cold water is denser than hot water  <br/> IV. metal wire is a good insulator <br/> Which of the above statements are correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III only</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heat cannot flow readily from the top to the bottom of the tube, since both the glass and the water are poor conductors. Also the heated water remains at the top because it is less dense than cold water.</div>", "topic": "HEAT TRANSFER"}, {"id": "objective>Physics>2018 Model I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following units is the S.I. unit of heat capacity?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">J k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">J g<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The heat capacity C of a substance is the amount of heat required to change its temperature by one degree, and has units of energy per degree.</div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2018 Model I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Diameter of a piece of wire <br/> II. Diameter of a piece of paper <br/> III. Diameter of a measuring cylinder <br/> IV. Length of a piece of wire <br/> Which of the above can be measured with a micrometer screw gauge.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I, II and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III and IV only</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The micrometer screw gauge is useful in the measurement of the diameter of a piece of wire, thickness (diameter) of a piece of paper.</div>", "topic": "MEASUREMENTS AND UNITS : LENGTH, AREA AND VOLUME"}, {"id": "objective>Physics>2018 Model I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When water condenses on the surface of a cup of cold water placed on a table, the temperature of the surrounding air </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decreases slightly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases slightly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remains unchanged </div>", "<div style=\"font-family:Cambria;font-size:17px;\">first decreases and then increases </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As the water condenses, heat of vaporization is evolved, which warms the surrounding air. Note that this is the exact opposite of the process of evaporation resulting in the cooling of the surroundings.</div>", "topic": "CHANGE OF STATE : SPECIFIC LATENT HEATS OF VAPORIZATION"}, {"id": "objective>Physics>2018 Model I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The effect of increased pressure on the transformation temperatures of water is that the  <br/> I. melting point is reduced <br/> II. melting point is increased <br/> III. boiling point is reduced <br/> IV. boiling point is increased <br/> Which of the above statements are correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and IV only</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct statements are: <br/>  <br/> I. Melting point is reduced <br/> IV. Boiling point is increased <br/>  <br/> Melting Point: Water expands when it freezes, meaning that applying pressure favors the liquid state over the solid. This causes the melting point to decrease under increased pressure. <br/>  <br/> Boiling Point: Higher pressure makes it harder for water molecules to escape into the gas phase, so the boiling point increases as pressure rises. <br/>  <br/> Thus, the correct answer is I and IV. <br/> </div>", "topic": "CHANGE OF STATE : EFFECT OF PRESSURE AND IMPURITIES ON BOILING AND MELTING POINTS"}, {"id": "objective>Physics>2018 Model I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above illustrates a wave form. Determine the speed of the wave.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.4ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.4ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.23ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.0ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">λ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">9<hr size=\"1\" />3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">3</td><td style=\"text-align:center;\">m</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.65<hr size=\"1\" />2</td><td style=\"text-align:center;\">s</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">f</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />0.65</td><td style=\"text-align:center;\">Hz</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">v</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">fλ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />0.65</td><td style=\"text-align:center;\">&#215;</td><td style=\"text-align:center;\">3</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">9.23ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td></tr></table></div></div>", "topic": "WAVES : PRODUCTION AND PROPAGATION"}, {"id": "objective>Physics>2018 Model I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following waves cannot be polarized?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">infra-red </div>", "<div style=\"font-family:Cambria;font-size:17px;\">yellow-light</div>", "<div style=\"font-family:Cambria;font-size:17px;\">x-rays </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sound </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sound, being a longitudinal wave, cannot be polarized. All the others are transverse waves, which can be polarized.</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2018 Model I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A slide of width 2.5cm is positioned 5.0cm from the lens of a projector. If the width of the image is 100cm, the distance from the lens to the screen is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">250cm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">500cm</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Magnification,</td><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">100<hr size=\"1\" />2.5</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">40</td></tr></table></div> <br/> Distance from the lens to the screen is  <br/> v = mu = 40(5) = 200cm <br/> </div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2018 Model I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Which of the following types of lenses is suitable for correcting the eye defect illustrated by the ray diagram above?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bi-converging</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bi-diverging</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Plano diverging</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Diverging meniscus</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In eyeglasses and contact lenses, biconvex lenses are used to correct hyperopia (farsightedness) by converging light rays onto the retina.</div>", "topic": "OPTICAL INSTRUMENTS : SIGHT DEFECTS AND THEIR CORRECTIONS"}, {"id": "objective>Physics>2018 Model I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A ball is released from a height of 125m above the ground. The time taken to reach the ground is ...... [g = 10m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10s</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">H= 125m, g = 10ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>, T = ? <br/> Recall: <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">2H<hr size=\"1\" />g</td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">T</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"></td><td style=\"text-align:center;\">250<hr size=\"1\" />10</td><td style=\"text-align:center;\">&nbsp;</span></td></tr></table></div> <br/> T = &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">25&nbsp;</span> <br/> T = 5s</div>", "topic": "MOTION: MOTION UNDER GRAVITY"}, {"id": "objective>Physics>2018 Model I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An aircraft travelled from a point X to a point Y 100km away in the N45°E direction. It then travelled westwards to a point Z which is N45°W from X. The distance of the aircraft from X is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50km</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">100<hr size=\"1\" />&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span></td><td style=\"text-align:center;\">km</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\">100km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">2&nbsp;</span>km</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2018 Model I/AP8J92.png\" style=\"position:relative;max-width:100%;\"/> <br/> Since the triangle is isosceles, a = 100km</div>", "topic": "SCALARS AND VECTORS"}, {"id": "objective>Physics>2018 Model I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The changes in temperature as heat is added to equal masses of two substances P and Q are indicated in the diagram above. From the diagram, it can be deduced that the  <br/> I. specific heat of Q is greater than of P <br/> II. specific heat of P is greater than that of Q <br/> III. thermal capacity of P is greater than that of Q <br/> Which of the above statements is(are) correct? <br/>  <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and IV only</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heat added = mass × specific heat × temp. change  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Temperature</td><td style=\"text-align:center;\">change</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Heat added<hr size=\"1\" />mass*time*specific heat</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Heat added<hr size=\"1\" />thermal capacity</td></tr></table></div> <br/> For any given value of heat added (see figure). P shows a lower temperature change and therefore has higher specific heat and higher thermal capacity.</div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2018 Model I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 20kg of water is allowed to cool from 75°C to 25°C. <br/> The quantity of heat loss is ...... <br/> [If S.H.C of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O = 4.2Jg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>°C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.2 KJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.2 MJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.2 GJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.2 TJ</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">M<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span> = 20kg = 20 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>g <br/> Δθ = 75°C - 25°C = 50°C <br/> Q = ?, c = 4.2 Jg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>°C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> Recall: Q = mCΔθ ------ (1) <br/> Q = 20 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> × 4.2 × 50 <br/>  = 84 × 50 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  = 85 × 50 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  = 4200 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  = 4.2 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> <br/>  = 4.2 MJ <br/> 4.2 MJ is the quantity of heat energy needed to cause that temperature change in the given mass of water</div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2018 Model I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A given mass of a gas occupies 120cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at s.t.p. Determine its volume at 273°C and 570mmHg.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">320cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">280cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">240cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">180cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = Standard temperature = 273K <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = Standard pressure = 760mmHg <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 120cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = unknown <br/> T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 273°C = 546K <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 570mmHg <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div> <br/> {General gas equation} <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">760 × 120<hr size=\"1\" />273</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">570 × V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />546</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">760</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">120</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">570V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />2</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">4</td><td style=\"text-align:center;\">×</td><td style=\"text-align:center;\">40</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />2</td></tr></table></div> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 320cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2018 Model I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> A fixed mass of gas is heated at constant volume so that its Celsius temperature is doubled. The pressure of the gas </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is halved </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is doubled </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is more than doubled </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increases but is less than doubled</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pressure is directly proportional to the absolute, not the Celsius temperature. Thus  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />2T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273<hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2(T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273)<hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">273<hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">273<hr size=\"1\" />T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+273</td></tr></table></div> <br/> Hence P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> is greater than one but less than 2</div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2018 Model I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A box of mass 10kg rests on a plane inclined at an angle of 30° to the horizontal. The coefficient of friction between the surface and the box is 0.2, If a force of 60N is applied parallel to the plane in an attempt to slide the box up the plane, the box will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">accelerate up the plane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">accelerate down the plane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">remain at rest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slide down the plane at a uniform speed</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The two forces acting down the plane are the resolved component of the box's weight = Wsin30° = 100sin30° <br/> = 50N, and  <br/> the limiting frictional force = μWcos30° <br/>  = 0.2(100)cos30° = 17.3N <br/> The combined downward force (67.3N) is greater than the upward force, hence the box will accelerate down the plane.</div>", "topic": "FRICTION"}];
